hooks.command:
ROOT="${CLAUDE_PROJECT_DIR:-$(git -C "$(dirname "${BASH_SOURCE[0]:-$0}")" rev-parse --show-toplevel 2>/dev/null || pwd)}"
TF="$ROOT/.sessions/session_tokens.md"
lw=$(grep "^LOOP_WEIGHT:" "$TF" 2>/dev/null | awk '{print $2}'); lw=${lw:-0}
st=$(grep "^SESSION_TOTAL:" "$TF" 2>/dev/null | awk '{print $2}'); st=${st:-0}
ct=$(grep "^CHAT_TOTAL:" "$TF" 2>/dev/null | awk '{print $2}'); ct=${ct:-0}
tc=$(grep "^TURN_COUNT:" "$TF" 2>/dev/null | awk '{print $2}'); tc=${tc:-0}
fr=$(grep "^FILES_READ:" "$TF" 2>/dev/null | awk '{print $2}'); fr=${fr:-0}
lo=$(grep "^LONG_OUTPUTS:" "$TF" 2>/dev/null | awk '{print $2}'); lo=${lo:-0}
reset_marker=$(grep "^session_reset[[:space:]]*[:=]" "$ROOT/.sessions/compact_state.md" 2>/dev/null | sed 's/^session_reset[[:space:]]*[:=][[:space:]]*//' | tr -d ' ')
if [ "$reset_marker" = "armed" ]; then
  lw=0; st=0; tc=0; fr=0; lo=0
  printf "SESSION_TOTAL: 0\nCHAT_TOTAL: %s\nCACHE_READ: 0\nCACHE_WRITE: 0\nTURN_COUNT: 0\nLOOP_WEIGHT: 0\nFILES_READ: 0\nLONG_OUTPUTS: 0\n" "$ct" > "$TF"
  sed -i '' "s/^session_reset[[:space:]]*[:=][[:space:]]*armed/session_reset: consumed/" "$ROOT/.sessions/compact_state.md" 2>/dev/null || sed -i "s/^session_reset[[:space:]]*[:=][[:space:]]*armed/session_reset: consumed/" "$ROOT/.sessions/compact_state.md" 2>/dev/null
fi
tc=$((tc+1))
sed -i '' "s/^TURN_COUNT:.*/TURN_COUNT: $tc/" "$TF" 2>/dev/null || sed -i "s/^TURN_COUNT:.*/TURN_COUNT: $tc/" "$TF" 2>/dev/null
sl=$(grep -cE "^- \[ \]|^- \[/\]" "$ROOT/.sessions/mece_plan.md" 2>/dev/null); sl=${sl:-0}
b=0; reasons=""
[ "$tc" -ge 20 ] 2>/dev/null && { b=$((b+1)); reasons="${reasons}turns=$tc "; }
[ "$fr" -ge 5 ] 2>/dev/null && { b=$((b+1)); reasons="${reasons}files=$fr "; }
[ "$lo" -ge 3 ] 2>/dev/null && { b=$((b+1)); reasons="${reasons}long_out=$lo "; }
[ "$sl" -ge 3 ] 2>/dev/null && { b=$((b+1)); reasons="${reasons}steps_left=$sl "; }
echo "[signal-box] $b/4 (turns=$tc files=$fr long_out=$lo steps_left=$sl) -- PRIMARY compact signal: drift-proof booleans (T-221)"
WIN=128000; CF=175; eff=$((ct*CF/100)); pct=$((eff*100/WIN))
if [ "$eff" -ge $((WIN*90/100)) ] 2>/dev/null && [ "$b" -ge 2 ] 2>/dev/null; then
  echo "[compact-STOP] WINDOW CEILING eff=${eff} (${pct}% of WIN=${WIN}) CHAT=$ct b=$b/4 -- estimate x1.75-corrected + window-anchored + signal-box>=2 confirm - write compact_state.md - STOP"
elif [ "$b" -ge 2 ] 2>/dev/null || [ "$eff" -ge $((WIN*70/100)) ] 2>/dev/null; then
  echo "[compact-rec] signal-box $b/4 ($reasons)-- PRIMARY trigger: 2+ drift-proof signals fired - surface a /compact RECOMMENDATION per C0.5 BC (Recommend/Why/MUST-vs-SHOULD=SHOULD/Resume brief/Your call). NOT a STOP - user decides"
else
  [ "${ct:-0}" -gt 80000 ] 2>/dev/null && echo "[compact-note] CHAT_TOTAL=$ct>80k (SECONDARY rough estimate - may be inflated by subagent pollution CFP-041; trust signal-box first)"
  [ "$lw" -gt 50 ] 2>/dev/null && echo "[compact-note] LOOP_WEIGHT=$lw>50 (SECONDARY tool-call hint; not a ceiling)"
fi
echo "[token-state] SESSION=${st} LOOP_W=${lw} CHAT=${ct} TURN=${tc} FILES=${fr} LONG_OUT=${lo} BOX=${b}/4 -- footer: use these values ONLY (CFP-031). signal-box=PRIMARY; SESSION/CHAT=secondary estimate"
exit 0

python3 -c "
import json, sys, os, subprocess
data = json.load(sys.stdin)
tool = data.get('tool_name', '')
file_path = data.get('tool_input', {}).get('file_path', '') or data.get('tool_input', {}).get('notebook_path', '')
rel_path = file_path.replace(os.sep, '/').lstrip('/')

PROHIBITED = [
    'knowledge/index_variables.json',
    'knowledge/index_files.json',
    'CODING_FAILURE_PATTERNS.md',
    'docs/master_roadmap.md',
    'INVARIANTS.md',
    'knowledge/error_index.md',
]

if tool == 'Read':
    for p in PROHIBITED:
        if rel_path.endswith(p) or p in rel_path:
            print(f'[gate] never-full-load: {p} is prohibited — use grep/offset only', file=sys.stderr)
            sys.exit(1)
    sys.exit(0)

if tool not in ('Edit', 'Write', 'NotebookEdit'):
    sys.exit(0)

# Close-gate: block phase:done write until .close_checklist_ack exists
if tool in ('Edit', 'Write') and ('active_thread.md' in rel_path or rel_path.endswith('active_thread.md')):
    new_string = data.get('tool_input', {}).get('new_string', '') or data.get('tool_input', {}).get('content', '')
    if 'phase: done' in new_string:
        root_cg = os.environ.get('CLAUDE_PROJECT_DIR')
        if not root_cg:
            try:
                root_cg = subprocess.check_output(['git','rev-parse','--show-toplevel'], stderr=subprocess.DEVNULL, cwd=os.getcwd()).decode().strip()
            except Exception:
                root_cg = os.getcwd()
        ack = os.path.join(root_cg, '.sessions', '.close_checklist_ack')
        if not os.path.exists(ack):
            print('[close-gate] BLOCKED: .close_checklist_ack missing — must Read mece_plan_schema.md §Close Checklist + touch .sessions/.close_checklist_ack before writing phase: done', file=sys.stderr)
            sys.exit(1)
        if not os.environ.get('HARNESS_SKIP_INDEX_BLOCK'):
            try:
                chk = subprocess.run(['python3', os.path.join(root_cg,'scripts','index_reconcile.py'),'--check'], capture_output=True, text=True, timeout=40)
                if chk.returncode == 2:
                    sys.stderr.write(chk.stderr)
                    print('[close-gate] BLOCKED: index/doc-ref drift unhealed - run python3 scripts/index_reconcile.py to heal, then retry (or HARNESS_SKIP_INDEX_BLOCK=1 to override).', file=sys.stderr)
                    sys.exit(1)
            except Exception:
                pass
        try:
            cfp_touched = os.path.join(root_cg, '.sessions', '.cfp_touched')
            block_cfp = False
            if os.path.exists(cfp_touched) and not os.environ.get('HARNESS_SKIP_CFP_BLOCK'):
                _lp = os.path.join(root_cg, '.sessions', 'self_improve_log.md')
                _td = __import__('datetime').date.today().isoformat()
                _logged = (os.path.exists(_lp) and __import__('datetime').date.fromtimestamp(os.path.getmtime(_lp)).isoformat() == _td)
                block_cfp = not _logged
        except Exception:
            block_cfp = False
        if block_cfp:
            print('[close-gate] BLOCKED: a CFP status changed this session (.cfp_touched) but self_improve_log.md not updated today - record the solution (loop stage 5) before phase:done, or HARNESS_SKIP_CFP_BLOCK=1 to override.', file=sys.stderr)
            sys.exit(1)

if rel_path.startswith('.sessions/'):
    sys.exit(0)
if '.sessions/' in rel_path:
    sys.exit(0)
root = os.environ.get('CLAUDE_PROJECT_DIR')
if not root:
    try:
        root = subprocess.check_output(['git','rev-parse','--show-toplevel'], stderr=subprocess.DEVNULL, cwd=os.getcwd()).decode().strip()
    except Exception:
        root = os.getcwd()
today = __import__('datetime').date.today().isoformat()
gather = os.path.join(root, '.sessions', 'gather_complete.md')
mece = os.path.join(root, '.sessions', 'mece_plan.md')
errors = []
if not os.path.exists(gather):
    errors.append('[gate] gather_complete.md missing — run Phase 1 first')
else:
    content = open(gather).read()
    if today not in content:
        errors.append('[gate] gather_complete.md stale (not today) — re-run Phase 1')
if not os.path.exists(mece):
    errors.append('[gate] mece_plan.md missing — run Phase 2 first')
else:
    content = open(mece).read()
    if today not in content:
        errors.append('[gate] mece_plan.md stale (not today) — re-run Phase 2')
if errors:
    print('\n'.join(errors), file=sys.stderr)
    sys.exit(1)
sys.exit(0)
"
